VALUES
  ('locality-d0d1b9a2-moex-00484', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初以$1,200,000取得機器設備，估計耐用年限為五年，無殘值。公司申報營利事 業所得稅時以直線法計提折舊，財務會計則採用年數合計法計提折舊。X2年底機器設備之帳面 金額為$480,000，課稅基礎為$720,000。所得稅稅率皆為20%，試問甲公司X2年底應認列：', '["增加遞延所得稅資產$16,000", "增加遞延所得稅資產$48,000", "增加遞延所得稅負債$16,000", "增加遞延所得稅負債$48,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00485', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日將成本$1,000,000、帳面金額$500,000，公允價值$700,000之機器， 以現金$800,000售予乙公司，並立即以每年租金$200,000租回三年，每年年底支付租金。甲 公司已移轉機器之控制予乙公司，故符合IFRS 15資產銷售之規定。甲公司得知租賃隱含利 率為10%。試問甲公司X1年應認列處理機器利益為何？', '["$86,466", "$157,894", "$300,000", "$302,630"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00486', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司訂有員工退休之確定福利計畫，該計畫之有關資訊如下：X1年1月1日之確定福利義 務現值為$1,000,000與計畫資產公允價值為$1,000,000。X1年度服務成本為$300,000，計畫資 產實際報酬為$170,000，另因退休金計畫精算假設變動產生精算損失$120,000。X1年12月31 日提撥退休金為$500,000，並支付退休金$100,000。已知折現率為10%。若精算師評估X1年 度該福利計畫之期末資產上限為$120,000，則甲公司 X1 年度應認列之其他綜合損益為何？ （不考慮所得稅影響數）', '["無其他綜合損益", "其他綜合損失$50,000", "其他綜合損失$80,000", "其他綜合損失$120,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00487', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司承包一項長期工程合約，採完工百分比法認列，該工程符合隨時間經過滿足之履約義 務，甲公司依投入成本衡量該工程之完工比例。該工程於 X1 年初以合約價格$1,000,000 承 包，預計三年完成工程，該合約之結果能可靠估計，其相關資料如下： X1年度 X2年度 X3年度 實際發生的合約成本 $270,000 $465,000 $165,000 至完工尚須投入成本 $630,000 $315,000 試問甲公司X2年度及X3年度應認列之工程損益為何? X2年度 X3年度', '["工程損失$20,000 工程利益$30,000", "工程損失$35,000 工程利益$100,000", "工程損失$65,000 工程利益$135,000", "工程損失$80,000 工程利益$150,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00488', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年初以$1,000,000購入機器，估計耐用年限5年，無殘值，直線法計提折舊，並 採用重估價模式衡量，每年重估價。X1 年底機器的公允價值$700,000，X2 年底機器的公允 價值$650,000。評估折舊方法、耐用年限與殘值皆不變下，則甲公司對於該機器在X2年度之 重估價對綜合損益表影響，下列敘述何者正確？（不考慮所得稅影響數）', '["無淨利影響，認列其他綜合損益增加$125,000", "認列重估價損失迴轉利益$75,000，其他綜合損益增加$50,000", "認列重估價損失迴轉利益$100,000，其他綜合損益增加$25,000", "認列重估價損失迴轉利益$125,000，無其他綜合損益影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00489', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司於X1年1月1日以$1,027,751發行面額$1,000,000，票面利率5%，三年到期，每年年 底付息一次，有效利率4%之可轉換公司債。經評估於公司債發行時，相同條件但不可轉換之 公司債，其市場利率為6%。X1年初所得稅稅率20%，無其他財稅差異。試問X1年1月1 日發行日考慮所得稅影響，則下列分錄何者正確？', '["貸記資本公積－認股權$43,585，貸記遞延所得稅負債$10,896", "貸記資本公積－認股權$54,481，借記遞延所得稅資產$10,896", "貸記公司債溢價$27,751，貸記遞延所得稅負債$5,550", "借記公司債折價$26,730，借記遞延所得稅資產$5,346"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00490', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲、乙兩家公司於2021年8月1日進行設備交換，已知相關資料如下： 甲公司設備 乙公司設備 原始成本 $100,000 $100,000 至8/1為止之累計折舊 49,000 42,000 8/1當日之公允價值 60,000 75,000 若此項交換對甲公司而言具有商業實質，對乙公司而言缺乏商業實質，下列敘述何者正確？', '["甲公司認列交換利益$9,000", "甲公司收到現金$15,000", "乙公司認列交換利益$17,000", "乙公司收到現金$17,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00491', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '三星公司2020年度之淨利為$821,000，其他相關資料如下：（1）2020年全年有20,000股， 每股面額$100，4%之累積特別股流通在外。（2）2020年1月1日流通在外普通股100,000股， 4月1日現金發行20,000股，7月1日發放10%股票股利，10月1日買回庫藏股12,000股， 12月1日進行1股分為2股之股份分割。試計算2020年每股盈餘：', '["$3", "$3.25", "$6", "$6.25"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00492', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '星星公司於2013年10月1日以現金$80,000取得月亮公司40%股權，月亮公司2013年1月 1日之淨資產帳面價值為$150,000，2013全年淨利$25,000，並於7月1日宣告並發放現金股 利$15,000。星星公司取得股權時，月亮公司淨資產中只有建築物之帳面價值低估$20,000，其 使用年限仍有 20 年，其餘淨資產之帳面價值皆等於公允價值。2013 年底星星公司股權投資 科目金額為何？', '["$89,600", "$76,400", "$82,600", "$82,400"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL),
  ('locality-d0d1b9a2-moex-00493', 'locality-d0d1b9a2', 'locality-d0d1b9a2-moex-110-78566e18', 'sub-locality-d0d1b9a2-01', NULL, 'single_choice', '甲公司現金流量表採用「改良式間接法」表達，並以「本期稅前淨利」調整非現金項目方式 進行，公司將支付利息列為籌資活動之現金流量。X2年度的財務報表顯示下列資料： 本期稅前淨利 $1,000,000 所得稅費用 $200,000 折舊費用 $100,000 呆帳費用 $50,000 利息費用 $250,000 應收帳款淨額減少 $300,000 存貨增加 $40,000 應付帳款增加 $250,000 應付利息增加 $30,000 應付公司債折價攤銷 $20,000 試問甲公司X2年度「營業產生之現金流量」金額為何？', '["$1,600,000", "$1,650,000", "$1,700,000", "$1,860,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:34:09+00:00", "source_pdf_sha1": "e7d62f420309", "answer_pdf_sha1": "1da4fc535389", "source_family": "moex-gov-tw", "moex": {"exam_code": "110190", "c": "313", "s": "1510", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中級會計學", "year": "110", "exam_name": "110年特種考試地方政府公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "locality", "civil_category": "會計"}'::jsonb, NULL)
